// NZ Slang Quiz — vanilla JS, no build step. Data comes from data.js
// (window.SLANG_DATA), generated by scripts/build-data.py.
(function () {
  "use strict";

  var DATA = (window.SLANG_DATA || []).filter(function (e) {
    return e.term && e.meaning;
  });

  // --- DOM helpers ---------------------------------------------------------
  var $ = function (id) { return document.getElementById(id); };
  var screens = { start: $("start"), quiz: $("quiz"), results: $("results") };
  function show(name) {
    Object.keys(screens).forEach(function (k) {
      screens[k].classList.toggle("hidden", k !== name);
    });
  }

  // --- utilities -----------------------------------------------------------
  function shuffle(arr) {
    var a = arr.slice();
    for (var i = a.length - 1; i > 0; i--) {
      var j = Math.floor(Math.random() * (i + 1));
      var t = a[i]; a[i] = a[j]; a[j] = t;
    }
    return a;
  }
  function sample(arr, n) { return shuffle(arr).slice(0, n); }
  function escapeHtml(s) {
    return String(s).replace(/[&<>"']/g, function (c) {
      return { "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c];
    });
  }
  var LETTERS = ["A", "B", "C", "D"];

  // --- categories ----------------------------------------------------------
  var counts = {};
  DATA.forEach(function (e) { counts[e.category] = (counts[e.category] || 0) + 1; });
  // Only categories with enough terms to form a quiz get their own option.
  var bigCats = Object.keys(counts).filter(function (c) { return counts[c] >= 6; })
    .sort(function (a, b) { return counts[b] - counts[a]; });

  var catSelect = $("category");
  var allOpt = document.createElement("option");
  allOpt.value = "__all__";
  allOpt.textContent = "All categories (" + DATA.length + " terms)";
  catSelect.appendChild(allOpt);
  bigCats.forEach(function (c) {
    var o = document.createElement("option");
    o.value = c;
    o.textContent = titleCase(c) + " (" + counts[c] + ")";
    catSelect.appendChild(o);
  });
  function titleCase(s) {
    return s.toLowerCase().replace(/\b\w/g, function (m) { return m.toUpperCase(); });
  }
  $("poolInfo").textContent = DATA.length + " slang terms loaded.";

  // --- quiz state ----------------------------------------------------------
  var state = null;

  function buildQuestions(pool, n, mode) {
    var picks = sample(pool, Math.min(n, pool.length));
    return picks.map(function (correct) {
      // Distractors: prefer same category, fall back to whole dataset.
      var sameCat = DATA.filter(function (e) {
        return e.category === correct.category && e.term !== correct.term;
      });
      var distractorPool = sameCat.length >= 3 ? sameCat : DATA.filter(function (e) {
        return e.term !== correct.term;
      });

      var field = mode === "meaning2term" ? "term" : "meaning";
      var distractors = [];
      var usedValues = {};
      usedValues[correct[field].toLowerCase()] = true;
      shuffle(distractorPool).some(function (e) {
        var v = e[field].toLowerCase();
        if (usedValues[v]) return false;
        usedValues[v] = true;
        distractors.push(e);
        return distractors.length >= 3;
      });

      var optionEntries = shuffle([correct].concat(distractors));
      return {
        correct: correct,
        mode: mode,
        options: optionEntries.map(function (e) {
          return { text: e[field], isCorrect: e === correct };
        }),
      };
    });
  }

  function startQuiz() {
    var cat = catSelect.value;
    var n = parseInt($("length").value, 10);
    var mode = $("mode").value;
    var pool = cat === "__all__" ? DATA : DATA.filter(function (e) { return e.category === cat; });
    if (pool.length < 4) { alert("Not enough terms in this category."); return; }

    state = {
      mode: mode,
      questions: buildQuestions(pool, n, mode),
      idx: 0,
      right: 0,
      wrong: 0,
      answered: false,
    };
    show("quiz");
    renderQuestion();
  }

  function renderQuestion() {
    var q = state.questions[state.idx];
    state.answered = false;

    $("sQ").textContent = state.idx + 1;
    $("sR").textContent = state.right;
    $("sW").textContent = state.wrong;
    $("qnum").textContent = "Question " + (state.idx + 1) + " / " + state.questions.length;
    $("bar").style.width = ((state.idx) / state.questions.length * 100) + "%";
    $("chip").textContent = titleCase(q.correct.category);

    if (state.mode === "meaning2term") {
      $("prompt").textContent = "Which Kiwi slang term means…";
      $("term").textContent = q.correct.meaning;
      $("term").style.fontSize = "26px";
    } else {
      $("prompt").textContent = "What does this slang mean?";
      $("term").textContent = q.correct.term;
      $("term").style.fontSize = "34px";
    }

    var box = $("options");
    box.innerHTML = "";
    q.options.forEach(function (opt, i) {
      var btn = document.createElement("button");
      btn.className = "opt";
      btn.innerHTML = '<span class="key">' + LETTERS[i] + "</span><span>" + escapeHtml(opt.text) + "</span>";
      btn.addEventListener("click", function () { answer(i); });
      box.appendChild(btn);
    });

    // Reset the example hint for this question.
    var hintBox = $("hintBox");
    if (q.correct.example) {
      hintBox.classList.remove("hidden");
      $("hintBtn").style.display = "";
      $("hintText").classList.remove("show");
    } else {
      hintBox.classList.add("hidden");
    }

    $("reveal").classList.remove("show");
    $("nextBtn").disabled = true;
    $("nextBtn").textContent = state.idx === state.questions.length - 1 ? "See results →" : "Next →";
  }

  // Blank out the term inside its example so the hint doesn't give away
  // the answer in "guess the term" mode.
  function maskExample(example, term) {
    var safe = term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    var re = new RegExp(safe, "ig");
    var isLetter = function (ch) { return !!ch && /[A-Za-z]/.test(ch); };
    var out = "", last = 0, m;
    while ((m = re.exec(example)) !== null) {
      // Only blank whole-word matches, so a short term like "g" doesn't
      // also blank the "g" inside "good".
      var atWordBoundary = !isLetter(example[m.index - 1]) &&
                           !isLetter(example[m.index + m[0].length]);
      out += escapeHtml(example.slice(last, m.index));
      out += atWordBoundary
        ? '<span class="mask">' + new Array(Math.max(3, m[0].length) + 1).join("_") + "</span>"
        : escapeHtml(m[0]);
      last = m.index + m[0].length;
      if (m.index === re.lastIndex) re.lastIndex++;
    }
    out += escapeHtml(example.slice(last));
    return out;
  }

  function revealHint() {
    if (!state) return;
    var q = state.questions[state.idx];
    if (!q || !q.correct.example) return;
    $("hintExampleText").innerHTML = state.mode === "meaning2term"
      ? maskExample(q.correct.example, q.correct.term)
      : escapeHtml(q.correct.example);
    $("hintText").classList.add("show");
    $("hintBtn").style.display = "none";
  }

  function answer(chosen) {
    if (state.answered) return;
    state.answered = true;
    var q = state.questions[state.idx];
    var buttons = $("options").querySelectorAll(".opt");
    var correctIdx = -1;
    q.options.forEach(function (o, i) { if (o.isCorrect) correctIdx = i; });

    buttons.forEach(function (b) { b.disabled = true; });
    buttons[correctIdx].classList.add("correct");

    var isRight = q.options[chosen].isCorrect;
    if (isRight) {
      state.right++;
    } else {
      state.wrong++;
      buttons[chosen].classList.add("wrong");
    }
    $("sR").textContent = state.right;
    $("sW").textContent = state.wrong;

    var verdict = $("verdict");
    verdict.textContent = isRight ? "✓ Correct!" : "✗ Not quite — “" + q.correct.term + "” means: " + q.correct.meaning;
    verdict.className = "verdict " + (isRight ? "good" : "bad");

    if (q.correct.example) {
      $("example").style.display = "";
      $("exampleText").textContent = q.correct.example;
    } else {
      $("example").style.display = "none";
    }

    // Dictionary lookup link (base form, dropping any |-joined variants).
    var lookup = q.correct.term.split("|")[0].trim();
    $("dictTerm").textContent = lookup;
    $("dictLink").href = "https://www.urbandictionary.com/define.php?term=" +
      encodeURIComponent(lookup);
    $("hintBox").classList.add("hidden");
    $("reveal").classList.add("show");
    $("nextBtn").disabled = false;
    $("bar").style.width = ((state.idx + 1) / state.questions.length * 100) + "%";
  }

  function next() {
    if (!state.answered) return;
    if (state.idx >= state.questions.length - 1) {
      showResults();
    } else {
      state.idx++;
      renderQuestion();
    }
  }

  function showResults() {
    var total = state.questions.length;
    var pct = Math.round(state.right / total * 100);
    $("scorePct").textContent = pct + "%";
    $("scoreDetail").textContent = state.right + " right · " + state.wrong + " wrong · " + total + " questions";
    var msg;
    if (pct === 100) msg = "Choice as! A true legend. 🏆";
    else if (pct >= 80) msg = "Sweet as — you know your slang! 🔥";
    else if (pct >= 60) msg = "Not bad, eh. Keep at it. 👍";
    else if (pct >= 40) msg = "Bit of a mish, but you're learning. 📚";
    else msg = "Hard yakka ahead — give it another crack! 💪";
    $("scoreMsg").textContent = msg;
    show("results");
  }

  // --- keyboard shortcuts (1-4 / A-D to answer, Enter/→ for next) ---------
  document.addEventListener("keydown", function (e) {
    if (screens.quiz.classList.contains("hidden")) return;
    if (!state) return;
    if (!state.answered) {
      if (e.key.toLowerCase() === "h") { e.preventDefault(); revealHint(); return; }
      var idx = -1;
      if (e.key >= "1" && e.key <= "4") idx = parseInt(e.key, 10) - 1;
      var up = e.key.toUpperCase();
      if (LETTERS.indexOf(up) !== -1) idx = LETTERS.indexOf(up);
      if (idx >= 0 && idx < $("options").children.length) { e.preventDefault(); answer(idx); }
    } else if (e.key === "Enter" || e.key === "ArrowRight" || e.key === " ") {
      e.preventDefault();
      next();
    }
  });

  // --- theme toggle --------------------------------------------------------
  function syncThemeLabel() {
    var dark = document.documentElement.getAttribute("data-theme") === "dark";
    var lbl = $("themeLabel");
    if (lbl) lbl.textContent = dark ? "Dark" : "Light";
  }
  syncThemeLabel();
  $("themeToggle").addEventListener("click", function () {
    var root = document.documentElement;
    var dark = root.getAttribute("data-theme") === "dark";
    if (dark) root.removeAttribute("data-theme");
    else root.setAttribute("data-theme", "dark");
    try { localStorage.setItem("slangquiz-theme", dark ? "light" : "dark"); } catch (e) {}
    syncThemeLabel();
  });

  // --- wiring --------------------------------------------------------------
  $("startBtn").addEventListener("click", startQuiz);
  $("hintBtn").addEventListener("click", revealHint);
  $("nextBtn").addEventListener("click", next);
  $("quitBtn").addEventListener("click", function () { show("start"); });
  $("againBtn").addEventListener("click", startQuiz);
  $("reviewHomeBtn").addEventListener("click", function () { show("start"); });

  if (!DATA.length) {
    $("poolInfo").textContent = "⚠️ No data loaded. Run scripts/build-data.py first.";
    $("startBtn").disabled = true;
  }
})();
